	"github.com/hashicorp/consul/agent/consul/state"
	"github.com/hashicorp/consul/agent/structs"
	"github.com/hashicorp/go-hclog"
	"github.com/hashicorp/go-memdb"
	"github.com/hashicorp/go-retryablehttp"
)

type ReportingManager struct {
	logger                      hclog.Logger
	clusterId                   string
	autoReporting               bool
	server                      ServerDelegate
	stateProvider               StateDelegate
	tickerInterval              time.Duration
	manualSnapshotInterval      time.Duration
	snapshotRetention           time.Duration
	initialMetricsRetryInterval time.Duration
	initialMetricsTimeout       time.Duration
	customerID                  string
	EntDeps
	sync.RWMutex
	manualHTTPClient     *retryablehttp.Client
	manualServiceAddress string
}

const (
	SystemMetadataReportingProcessID = "reporting-process-id"
	ReportingInterval                = 1 * time.Hour
)

const (
	// ManualSnapshotInterval controls how often we persist manual census snapshots.
	ManualSnapshotInterval = 24 * time.Hour
	// DefaultSnapshotRetention is the default retention period for manual census snapshots.
	DefaultSnapshotRetention = 9600 * time.Hour // 400 days
)

const (
	defaultInitialMetricsRetryInterval = 500 * time.Millisecond
	defaultInitialMetricsTimeout       = 30 * time.Second
)

//go:generate mockery --name ServerDelegate --inpackage
type ServerDelegate interface {
	GetSystemMetadata(key string) (string, error)
	SetSystemMetadataKey(key, val string) error
	IsLeader() bool
	ApplyCensusRequest(req *structs.CensusRequest) error
}

type StateDelegate interface {
--- rate handler
	Run(ctx context.Context)
	Allow(op Operation) error
	UpdateConfig(cfg HandlerConfig)
	UpdateIPConfig(cfg IPLimitConfig)
	Register(serversStatusProvider ServersStatusProvider)
	UpdateGlobalRateLimitConfig(cfg *structs.GlobalRateLimitConfigEntry)
}

// Handler enforces rate limits for incoming RPCs.
type Handler struct {
	globalCfg             *atomic.Pointer[HandlerConfig]
	ipCfg                 *atomic.Pointer[IPLimitConfig]
	globalRateLimitCfg    *atomic.Pointer[structs.GlobalRateLimitConfigEntry]
	serversStatusProvider ServersStatusProvider

	limiter multilimiter.RateLimiter

	logger hclog.Logger
}

type ReadWriteConfig struct {
	// WriteConfig configures the global rate limiter for write operations.
	WriteConfig multilimiter.LimiterConfig

	// ReadConfig configures the global rate limiter for read operations.
	ReadConfig multilimiter.LimiterConfig
}

type GlobalLimitConfig struct {
	Mode Mode
	ReadWriteConfig
}

type HandlerConfig struct {
	multilimiter.Config

	GlobalLimitConfig GlobalLimitConfig
}

//go:generate mockery --name ServersStatusProvider --inpackage --filename mock_ServersStatusProvider_test.go
type ServersStatusProvider interface {
	// IsLeader is used to determine whether the operation is being performed
	// against the cluster leader, such that if it can _only_ be performed by
